module watchdog_timer (
    input clk,
    input rst,
    input enable,
    input [3:0] timeout, // 4-bit timeout value
    output reg timeout_expired
);
    reg [3:0] wdt_count;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            wdt_count <= 4'b0000;
            timeout_expired <= 1'b0;
        end else if (enable) begin
            if (wdt_count < timeout) begin
                wdt_count <= wdt_count + 1;
                timeout_expired <= 1'b0;
            end else begin
                timeout_expired <= 1'b1; // Timeout has expired
            end
        end else begin
            wdt_count <= 4'b0000; // Reset wdt_count if not enabled
            timeout_expired <= 1'b0;
        end
    end
endmodule
